1	<script>
2		let angle = $state(90);
3		let dragging = false;
4		let svgEl;
5	
6		const candidates = [
7			{ id: 'c1', deg: 20 },
8			{ id: 'c2', deg: 70 },
9			{ id: 'c3', deg: 110 },
10			{ id: 'c4', deg: 160 }
11		];
12	
13		function toPoint(deg, r, cx = 200, cy = 200) {
14			const rad = (deg * Math.PI) / 180;
15			return { x: cx + r * Math.cos(rad), y: cy - r * Math.sin(rad) };
16		}
17	
18		// Offsets a point tangentially (sideways along the circle) so a label
19		// placed near an arrow's tip never sits directly on the arrow's line,
20		// even if another arrow later points at that same angle.
21		function toTangentPoint(deg, r, sideOffset, cx = 200, cy = 200) {
22			const rad = (deg * Math.PI) / 180;
23			return {
24				x: cx + r * Math.cos(rad) - sideOffset * Math.sin(rad),
25				y: cy - r * Math.sin(rad) - sideOffset * Math.cos(rad)
26			};
27		}
28	
29		const scores = $derived(
30			candidates.map((c) => {
31				const diff = ((angle - c.deg) * Math.PI) / 180;
32				return Math.round(100 * Math.cos(diff));
33			})
34		);
35	
36		const bestIndex = $derived(
37			scores.reduce((best, s, i) => (s > scores[best] ? i : best), 0)
38		);
39	
40		function angleFromClient(clientX, clientY) {
41			const rect = svgEl.getBoundingClientRect();
42			const cx = rect.left + rect.width / 2;
43			const cy = rect.top + rect.height / 2;
44			const dx = clientX - cx;
45			const dy = clientY - cy;
46			let a = (Math.atan2(-dy, dx) * 180) / Math.PI;
47			if (a < 0) a += 360;
48			return Math.round(a);
49		}
50	
51		function handlePointerDown(e) {
52			dragging = true;
53			svgEl.setPointerCapture(e.pointerId);
54			angle = angleFromClient(e.clientX, e.clientY);
55		}
56	
57		function handlePointerMove(e) {
58			if (!dragging) return;
59			angle = angleFromClient(e.clientX, e.clientY);
60		}
61	
62		function handlePointerUp(e) {
63			dragging = false;
64			try {
65				svgEl.releasePointerCapture(e.pointerId);
66			} catch (err) {
67				// already released, ignore
68			}
69		}
70	
71		function handleKeydown(e) {
72			let handled = true;
73			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') {
74				angle = Math.min(360, angle + 5);
75			} else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') {
76				angle = Math.max(0, angle - 5);
77			} else if (e.key === 'Home') {
78				angle = 0;
79			} else if (e.key === 'End') {
80				angle = 360;
81			} else {
82				handled = false;
83			}
84			if (handled) e.preventDefault();
85		}
86	
87		function fmt(n) {
88			return n > 0 ? `+${n}` : `${n}`;
89		}
90	
91		const probeTip = $derived(toPoint(angle, 148));
92		const probeLabel = $derived.by(() => {
93			const rad = (angle * Math.PI) / 180;
94			const shaftR = 80;
95			const sideOffset = 22;
96			return {
97				x: 200 + shaftR * Math.cos(rad) - sideOffset * Math.sin(rad),
98				y: 200 - shaftR * Math.sin(rad) - sideOffset * Math.cos(rad)
99			};
100		});
101	</script>
102	
103	<div data-interactive="dot-alignment" class="wrap">
104		<p class="instruction">Turn the probe (drag it or use arrow keys) until a bar peaks.</p>
105	
106		<div class="stage">
107			<svg
108				bind:this={svgEl}
109				class="dial"
110				viewBox="0 0 400 400"
111				role="slider"
112				tabindex="0"
113				aria-label="Probe angle in degrees"
114				aria-valuemin="0"
115				aria-valuemax="360"
116				aria-valuenow={angle}
117				aria-valuetext={`${angle} degrees`}
118				onpointerdown={handlePointerDown}
119				onpointermove={handlePointerMove}
120				onpointerup={handlePointerUp}
121				onpointercancel={handlePointerUp}
122				onkeydown={handleKeydown}
123			>
124				<defs>
125					<marker id="head-probe" markerWidth="10" markerHeight="10" refX="6" refY="5" orient="auto">
126						<path d="M0,0 L10,5 L0,10 Z" style="fill: var(--data-heat)" />
127					</marker>
128					<marker id="head-candidate" markerWidth="9" markerHeight="9" refX="5" refY="4.5" orient="auto">
129						<path d="M0,0 L9,4.5 L0,9 Z" style="fill: var(--data-observed)" />
130					</marker>
131				</defs>
132	
133				<circle cx="200" cy="200" r="160" fill="none" stroke="var(--color-text)" stroke-width="1" opacity="0.12" />
134				<circle cx="200" cy="200" r="4" fill="var(--color-text)" opacity="0.3" />
135	
136				{#each candidates as c, i}
137					{@const tip = toPoint(c.deg, 130)}
138					{@const lbl = toTangentPoint(c.deg, 160, 26)}
139					<line
140						x1="200"
141						y1="200"
142						x2={tip.x}
143						y2={tip.y}
144						stroke="var(--data-observed)"
145						stroke-width="3"
146						opacity={i === bestIndex ? 0.85 : 0.4}
147						marker-end="url(#head-candidate)"
148					/>
149					<text
150						x={lbl.x}
151						y={lbl.y}
152						text-anchor="middle"
153						dominant-baseline="middle"
154						class="tip-label"
155						style="fill: var(--color-text)"
156					>{c.id}</text>
157				{/each}
158	
159				<line
160					x1="200"
161					y1="200"
162					x2={probeTip.x}
163					y2={probeTip.y}
164					stroke="var(--data-heat)"
165					stroke-width="6"
166					marker-end="url(#head-probe)"
167				/>
168				<text
169					x={probeLabel.x}
170					y={probeLabel.y}
171					text-anchor="middle"
172					dominant-baseline="middle"
173					class="probe-label"
174					style="fill: var(--color-text)"
175				>probe {angle}°</text>
176			</svg>
177		</div>
178	
179		<div class="scores">
180			{#each candidates as c, i}
181				<div class="score-col" class:leading={i === bestIndex}>
182					<div class="score-name" style="color: var(--color-text)">{c.id}</div>
183					<div class="bar-track">
184						<div class="zero-line"></div>
185						{#if scores[i] >= 0}
186							<div class="bar pos" style="height: {Math.abs(scores[i]) * 0.55}px; opacity: {i === bestIndex ? 1 : 0.45}"></div>
187						{:else}
188							<div class="bar neg" style="height: {Math.abs(scores[i]) * 0.55}px; opacity: {i === bestIndex ? 1 : 0.45}"></div>
189						{/if}
190					</div>
191					<div class="score-num">{fmt(scores[i])}</div>
192				</div>
193			{/each}
194		</div>
195	</div>
196	
197	<style>
198		.wrap {
199			display: flex;
200			flex-direction: column;
201			align-items: center;
202			gap: clamp(0.75rem, 2.5vw, 1.25rem);
203			width: 100%;
204			max-width: 640px;
205			margin: 0 auto;
206			padding: clamp(0.75rem, 3vw, 1.5rem);
207			box-sizing: border-box;
208			font-family: var(--font-body);
209			color: var(--color-text);
210			background: var(--color-bg);
211		}
212	
213		.instruction {
214			margin: 0;
215			font-size: clamp(0.85rem, 1.6vw, 1rem);
216			opacity: 0.85;
217			text-align: center;
218		}
219	
220		.stage {
221			width: 100%;
222			max-width: 420px;
223		}
224	
225		.dial {
226			width: 100%;
227			height: auto;
228			aspect-ratio: 1 / 1;
229			display: block;
230			touch-action: none;
231			cursor: grab;
232		}
233	
234		.dial:focus-visible {
235			outline: 2px solid var(--data-heat);
236			outline-offset: 4px;
237		}
238	
239		.tip-label {
240			font-family: var(--font-mono);
241			font-size: 16px;
242		}
243	
244		.probe-label {
245			font-family: var(--font-mono);
246			font-size: 17px;
247			font-weight: 600;
248		}
249	
250		.scores {
251			display: flex;
252			justify-content: space-between;
253			gap: clamp(0.4rem, 2vw, 1rem);
254			width: 100%;
255			max-width: 460px;
256		}
257	
258		.score-col {
259			display: flex;
260			flex-direction: column;
261			align-items: center;
262			gap: 0.25rem;
263			flex: 1 1 0;
264			min-width: 0;
265		}
266	
267		.score-name {
268			font-family: var(--font-mono);
269			font-size: clamp(0.7rem, 1.6vw, 0.85rem);
270			opacity: 0.8;
271		}
272	
273		.bar-track {
274			position: relative;
275			width: 100%;
276			max-width: 44px;
277			margin: 0 auto;
278			height: 120px;
279			display: flex;
280			align-items: center;
281			justify-content: center;
282		}
283	
284		.zero-line {
285			position: absolute;
286			left: 0;
287			right: 0;
288			top: 50%;
289			height: 1px;
290			background: var(--color-text);
291			opacity: 0.2;
292		}
293	
294		.bar {
295			position: absolute;
296			width: 60%;
297			max-width: 26px;
298			background: var(--data-params);
299			border-radius: 2px;
300		}
301	
302		.bar.pos {
303			bottom: 50%;
304		}
305	
306		.bar.neg {
307			top: 50%;
308		}
309	
310		.leading .bar {
311			box-shadow: 0 0 0 1px var(--data-params);
312		}
313	
314		.score-num {
315			font-family: var(--font-mono);
316			font-size: clamp(0.7rem, 1.6vw, 0.8rem);
317			color: var(--data-params);
318			opacity: 0.75;
319		}
320	
321		.leading .score-num {
322			opacity: 1;
323			font-weight: 600;
324		}
325	
326		@media (prefers-reduced-motion: reduce) {
327			.dial,
328			.bar,
329			.score-num {
330				transition: none !important;
331				animation: none !important;
332			}
333		}
334	</style>
